import logging
import os
from datetime import timedelta

# Set up logging format and handlers
formatter = logging.Formatter('%(asctime)s - %(levelname)s - %(message)s')

# Create console handler
console_handler = logging.StreamHandler()
console_handler.setLevel(logging.INFO)
console_handler.formatter = formatter

# Create file handlers and set level to DEBUG for detailed logs
app_log_path = '/var/log/application/'
if not os.path.exists(app_log_path):
    os.makedirs(app_log_path)
file_handlers = []
for level in ['CRITICAL', 'ERROR', 'WARNING', 'INFO', 'DEBUG']:
    handler = logging.FileHandler(f'{app_log_path}{level}.log')
    handler.setLevel(getattr(logging, level))
    handler.formatter = formatter
    file_handlers.append(handler)

# Create root logger
root_logger = logging.getLogger()
root_logger.setLevel(logging.DEBUG)
root_logger.addHandler(console_handler)

for handler in file_handlers:
    root_logger.addHandler(handler)

# Configure log rotation (using logrotate - not directly supported by Python)
import sys
import subprocess

max_bytes = 10485760 # 10 MB
backup_count = 3
for handler in file_handlers:
    log_file = handler.baseFilename
    rotate_cmd = f'logrotate -f /etc/logrotate.d/application -s {sys.argv[0]} ' \
                f'{os.path.abspath(log_file)}'
    subprocess.run(rotate_cmd, shell=True)